const crypto = require('crypto');

function hashPassword(password, salt) {
  if (!salt) {
    salt = crypto.randomBytes(16).toString('hex');
  }
  const hash = crypto
    .createHmac('sha256', salt)
    .update(password)
    .digest('hex');
  return { salt, hash };
}

module.exports = hashPassword;